    fun `parseSourcesToFileScheme - path with special characters`() {
        val result = parseSourcesToFileScheme("<img src=magenta.png>", "storage/emulated/0/AnkiDroid@#$%/collection.media")
        assertEquals("""<img src="file:///storage/emulated/0/AnkiDroid@%23$%25/collection.media/magenta.png">""", result)
    }

    /**
     * Regression test for https://github.com/ankidroid/Anki-Android/issues/15773
     * Script tags were being stripped when a substitution took place
     */
    @Test
    fun `parseSourcesToFileScheme - script tags are preserved when substitution occurs`() {
        val mediaDir = "storage/emulated/0/AnkiDroid/collection.media"

        @Language("HTML")
        val content = """
            <script>
            var showHintsForPseudoClozes = true
            var underlineRevealedPseudoClozes = false
            </script>
            <div id="extra" class="content">
            <img src="paste-image.jpg" width="203">
            </div>
            <script>
            function toggleCloze(elem) { return elem; }
            </script>
        """.trimIndent()

        val result = parseSourcesToFileScheme(content, mediaDir)

        // Verify that script tags are preserved
        assert(result.contains("<script>")) { "Script opening tag should be preserved" }
        assert(result.contains("</script>")) { "Script closing tag should be preserved" }
        assert(result.contains("showHintsForPseudoClozes")) { "First script content should be preserved" }
        assert(result.contains("toggleCloze")) { "Second script content should be preserved" }
        // Verify that the image src was substituted
        assert(result.contains("file:///$mediaDir/paste-image.jpg")) { "Image src should be converted to file scheme" }
    }

    /***********************************************************************************************
     * [parseVideos] tests
     **********************************************************************************************/"}

